import React, { useState, useEffect, useRef, useCallback } from 'react';
import './App.css';
import { useSocket } from './useSocket';

// ─── Helpers ─────────────────────────────────────────────
function formatTime(ts) {
  return new Date(ts).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
}

function CharCount({ value, max }) {
  const remaining = max - value.length;
  const cls = remaining < 20 ? 'danger' : remaining < 60 ? 'warn' : '';
  if (remaining >= max - 10) return null;
  return <span className={`char-count ${cls}`}>{remaining}</span>;
}

// ─── Toast system ─────────────────────────────────────────
function Toast({ toasts }) {
  return (
    <div className="toast-container">
      {toasts.map((t) => (
        <div key={t.id} className="toast">{t.text}</div>
      ))}
    </div>
  );
}

// ─── Remote Audio Component ───────────────────────────────
function RemoteAudio({ stream }) {
  const audioRef = useRef(null);

  useEffect(() => {
    if (audioRef.current && stream) {
      audioRef.current.srcObject = stream;
    }
  }, [stream]);

  if (!stream) return null;
  return <audio ref={audioRef} autoPlay style={{ display: 'none' }} />;
}

// ─── Message Component ────────────────────────────────────
function Message({ msg, isMine, socketId, onReport, onReact }) {
  if (msg.isSystem) {
    return <div className="sys-msg">// {msg.text} //</div>;
  }

  // Reactions count mapping
  const reactionTypes = ['skull', 'blood', 'eye'];
  const emojis = { skull: '💀', blood: '🩸', eye: '👁️' };

  return (
    <div className={`msg-group ${isMine ? 'mine' : ''}`}>
      <div className="msg-avatar-wrap">{msg.avatar}</div>
      <div className="msg-body">
        <div className="msg-meta">
          <span className="msg-author">{isMine ? 'YOU' : msg.name}</span>
          {' · '}
          {formatTime(msg.ts)}
        </div>
        <div className="msg-bubble-wrap">
          <div className="msg-bubble">
            {msg.imageUrl && (
              <div className="msg-image-wrap">
                <img src={msg.imageUrl} alt="Shared from the void" className="msg-image" onClick={() => window.open(msg.imageUrl, '_blank')} />
              </div>
            )}
            {msg.text && <span className="msg-text">{msg.text}</span>}

            {/* Reaction popup trigger bar on hover */}
            <div className="msg-reaction-bar">
              {reactionTypes.map((type) => (
                <button
                  key={type}
                  className={`reaction-btn-icon ${
                    msg.reactions?.[type]?.includes(socketId) ? 'active' : ''
                  }`}
                  onClick={() => onReact(msg.id, type)}
                  title={`React with ${type}`}
                >
                  {emojis[type]}
                </button>
              ))}
            </div>
          </div>

          {/* Reaction badges displayed below the bubble */}
          {msg.reactions && Object.keys(msg.reactions).some(k => msg.reactions[k]?.length > 0) && (
            <div className="msg-reactions-list">
              {reactionTypes.map((type) => {
                const usersList = msg.reactions[type] || [];
                if (usersList.length === 0) return null;
                const userReacted = usersList.includes(socketId);
                return (
                  <button
                    key={type}
                    onClick={() => onReact(msg.id, type)}
                    className={`reaction-badge ${userReacted ? 'user-reacted' : ''}`}
                    title={userReacted ? 'You reacted. Click to remove.' : 'Click to react.'}
                  >
                    <span className="reaction-emoji">{emojis[type]}</span>
                    <span className="reaction-count">{usersList.length}</span>
                  </button>
                );
              })}
            </div>
          )}
        </div>
      </div>
      {!isMine && (
        <button
          className="msg-report"
          onClick={() => onReport(msg.id)}
          title="Report this soul"
        >
          ⚑
        </button>
      )}
    </div>
  );
}

// ─── Typing Bar ───────────────────────────────────────────
function TypingBar({ typingUsers }) {
  const typers = Object.values(typingUsers);
  if (typers.length === 0) return <div className="typing-bar" />;

  const label =
    typers.length === 1
      ? `${typers[0].avatar} ${typers[0].name} is whispering`
      : `${typers.length} souls are whispering`;

  return (
    <div className="typing-bar">
      <div className="typing-dots">
        <span /><span /><span />
      </div>
      {label}
    </div>
  );
}

// ─── Sidebar ──────────────────────────────────────────────
function Sidebar({
  identity,
  soulCount,
  connected,
  currentRoom,
  switchRoom,
  matchStatus,
  joinMatchmaking,
  leaveMatchmaking,
  isOpen,
  onClose,
  toggleAdmin
}) {
  const connClass = connected ? 'connected' : 'disconnected';
  const connLabel = connected ? 'CONNECTED' : 'RECONNECTING...';

  const channels = [
    { id: 'lobby', label: 'LOBBY', icon: '🩸' },
    { id: 'graveyard', label: 'GRAVEYARD', icon: '🪦' },
    { id: 'purgatory', label: 'PURGATORY', icon: '🕸️' },
    { id: 'abyss', label: 'THE ABYSS', icon: '🌑' },
  ];

  const inMatchMode = matchStatus === 'searching' || matchStatus === 'paired';

  return (
    <aside className={`sidebar ${isOpen ? 'open' : ''}`}>
      <div className="sidebar-header">
        <div className="logo">☠ VOID</div>
        <div className="logo-sub">ANONYMOUS CHAT</div>
      </div>

      {identity && (
        <div className="my-card">
          <div className="my-card-label">YOUR SOUL</div>
          <div className="my-identity">
            <div className="my-avatar">{identity.avatar}</div>
            <div className="my-name">
              {identity.name}
              <span>Anonymous</span>
            </div>
          </div>
        </div>
      )}

      {/* Matchmaking Section */}
      <div className="matchmaking-control">
        <div className="users-section-label">1-ON-1 MATCHMAKING</div>
        {matchStatus === 'idle' ? (
          <button className="match-mode-btn search-btn" onClick={joinMatchmaking} disabled={!connected}>
            🔮 Enter 1-on-1 Matching
          </button>
        ) : matchStatus === 'searching' ? (
          <button className="match-mode-btn leave-btn" onClick={leaveMatchmaking}>
            🚪 Leave Matching Mist
          </button>
        ) : (
          <div className="matched-active-indicator">
            <span className="pulse-dot active" /> Paired in Private Void
          </div>
        )}
      </div>

      {/* Channels / Realms List */}
      <div className="users-section">
        <div className="users-section-label">REALMS</div>
        <div className="channels-list">
          {channels.map((chan) => (
            <button
              key={chan.id}
              onClick={() => {
                if (inMatchMode) {
                  if (confirm("Leave matchmaking/1-on-1 mode to return to general channels?")) {
                    leaveMatchmaking();
                    switchRoom(chan.id);
                  }
                } else {
                  switchRoom(chan.id);
                }
              }}
              className={`channel-btn ${currentRoom === chan.id && !inMatchMode ? 'active' : ''}`}
            >
              <span className="chan-icon">{chan.icon}</span>
              <span className="chan-label">#{chan.label}</span>
            </button>
          ))}
        </div>
      </div>

      <div className="soul-count-wrap">
        <div className="soul-pulse" />
        <span className="soul-count-text">
          <strong>{soulCount}</strong> {soulCount === 1 ? 'soul' : 'souls'} online
        </span>
      </div>

      {/* Admin Action Toggle */}
      <div className="admin-toggle-wrap">
        <button className="admin-entry-btn" onClick={toggleAdmin}>
          ⚙️ Admin Console
        </button>
      </div>

      <div className="conn-status">
        <div className={`conn-dot ${connClass}`} />
        <span className={`conn-label ${connClass}`}>{connLabel}</span>
      </div>
    </aside>
  );
}

// ─── Main App ─────────────────────────────────────────────
export default function App() {
  const {
    connected,
    identity,
    messages,
    soulCount,
    typingUsers,
    sendMessage,
    reactToMessage,
    sendTypingStart,
    sendTypingStop,
    reportMessage,
    socketId,

    // Rooms
    currentRoom,
    switchRoom,

    // Matchmaking
    matchStatus,
    partner,
    joinMatchmaking,
    leaveMatchmaking,
    skipMatch,

    // Voice Chat
    isVoiceActive,
    isPartnerVoiceActive,
    toggleVoice,
    remoteStream,

    // Admin
    isAdmin,
    adminUsers,
    adminBans,
    adminError,
    authenticateAdmin,
    banUser,
    unbanUser,
    getBans,

    // Bans
    isBanned,
    banReason
  } = useSocket();

  const [input, setInput] = useState('');
  const [toasts, setToasts] = useState([]);
  const [showScrollBtn, setShowScrollBtn] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [showAdminConsole, setShowAdminConsole] = useState(false);
  const [adminTokenInput, setAdminTokenInput] = useState('');
  const [imagePreview, setImagePreview] = useState(null); // base64 representation of attached image

  const messagesEndRef = useRef(null);
  const messagesAreaRef = useRef(null);
  const typingTimerRef = useRef(null);
  const isAtBottomRef = useRef(true);
  const fileInputRef = useRef(null);

  const MAX_LEN = 300;

  // Check query parameter for admin token automatically
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const token = params.get('admin');
    if (token) {
      authenticateAdmin(token);
      setShowAdminConsole(true);
    }
  }, [authenticateAdmin]);

  // ── Auto-scroll ────────────────────────────────────────
  useEffect(() => {
    if (isAtBottomRef.current) {
      messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [messages]);

  const handleScroll = useCallback(() => {
    const el = messagesAreaRef.current;
    if (!el) return;
    const atBottom = el.scrollHeight - el.scrollTop - el.clientHeight < 80;
    isAtBottomRef.current = atBottom;
    setShowScrollBtn(!atBottom);
  }, []);

  const scrollToBottom = () => {
    isAtBottomRef.current = true;
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    setShowScrollBtn(false);
  };

  // ── Toasts ─────────────────────────────────────────────
  const addToast = useCallback((text) => {
    const id = Date.now();
    setToasts((prev) => [...prev, { id, text }]);
    setTimeout(() => setToasts((prev) => prev.filter((t) => t.id !== id)), 3500);
  }, []);

  // ── Typing ─────────────────────────────────────────────
  const handleInputChange = (e) => {
    setInput(e.target.value);
    sendTypingStart();
    clearTimeout(typingTimerRef.current);
    typingTimerRef.current = setTimeout(() => sendTypingStop(), 2500);
  };

  // ── Attach Image ───────────────────────────────────────
  const handleImageAttach = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    if (file.size > 1.5 * 1024 * 1024) {
      alert("This image is too heavy for the void. Max size is 1.5MB.");
      if (fileInputRef.current) fileInputRef.current.value = "";
      return;
    }

    const reader = new FileReader();
    reader.onload = () => {
      setImagePreview(reader.result);
    };
    reader.onerror = () => {
      alert("Error reading file.");
    };
    reader.readAsDataURL(file);
  };

  const removeAttachedImage = () => {
    setImagePreview(null);
    if (fileInputRef.current) fileInputRef.current.value = "";
  };

  // ── Send ───────────────────────────────────────────────
  const handleSend = () => {
    const text = input.trim();
    if (!text && !imagePreview) return;
    if (!connected) return;

    sendMessage(text, imagePreview);
    setInput('');
    setImagePreview(null);
    if (fileInputRef.current) fileInputRef.current.value = "";

    clearTimeout(typingTimerRef.current);
    sendTypingStop();
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  // ── Report ─────────────────────────────────────────────
  const handleReport = (msgId) => {
    reportMessage(msgId);
    addToast('⚑ Report sent. The void will judge them.');
  };

  // ── React ──────────────────────────────────────────────
  const handleReact = (msgId, reactionType) => {
    reactToMessage(msgId, reactionType);
  };

  // ── Admin console authentication toggle ────────────────
  const handleAdminToggle = () => {
    if (isAdmin) {
      setShowAdminConsole(!showAdminConsole);
    } else {
      const pass = prompt("Enter the admin key to speak to the master of the void:");
      if (pass !== null) {
        authenticateAdmin(pass);
        setShowAdminConsole(true);
      }
    }
  };

  const executeBan = (user) => {
    const reason = prompt(`Reason for banning ${user.name} (${user.avatar}):`, "Spamming the void");
    if (reason !== null) {
      banUser(user.id, user.deviceId, user.ipAddress, reason);
      addToast(`Exiled ${user.name} from the void.`);
    }
  };

  const executeUnban = (ban) => {
    const confirmUnban = window.confirm(`Unban device ${ban.deviceId || ban.ipAddress}?`);
    if (confirmUnban) {
      unbanUser(ban.deviceId || ban.ipAddress);
      addToast(`Unbanned soul.`);
    }
  };

  // Render full screen banned overlay
  if (isBanned) {
    return (
      <div className="banned-screen app">
        <div className="crt-overlay">
          <div className="crt-scanlines" />
          <div className="crt-vignette" />
        </div>
        <div className="banned-modal">
          <h1 className="exile-title">💀 YOU HAVE BEEN EXILED 💀</h1>
          <p className="exile-subtitle">Your soul has been cast out of the VOID.</p>
          <div className="exile-reason-box">
            <strong>REASON FOR EXILE:</strong>
            <p className="exile-reason">"{banReason || 'No reason was provided by the dark spirits.'}"</p>
          </div>
          <p className="exile-footer">You cannot wander back. The seals are locked.</p>
        </div>
      </div>
    );
  }

  const isMatched = matchStatus === 'paired';

  return (
    <div className="app">
      {/* CRT effect */}
      <div className="crt-overlay">
        <div className="crt-scanlines" />
        <div className="crt-vignette" />
      </div>

      {/* Sidebar backdrop (mobile only) */}
      <div
        className={`sidebar-backdrop ${sidebarOpen ? 'visible' : ''}`}
        onClick={() => setSidebarOpen(false)}
      />

      <Sidebar
        identity={identity}
        soulCount={soulCount}
        connected={connected}
        currentRoom={currentRoom}
        switchRoom={switchRoom}
        matchStatus={matchStatus}
        joinMatchmaking={joinMatchmaking}
        leaveMatchmaking={leaveMatchmaking}
        isOpen={sidebarOpen}
        onClose={() => setSidebarOpen(false)}
        toggleAdmin={handleAdminToggle}
      />

      {/* WebRTC Remote Audio Element */}
      <RemoteAudio stream={remoteStream} />

      <main className="chat-main">
        {/* Mobile top bar */}
        <div className="mobile-topbar">
          <div className="mobile-topbar__logo">
            {isMatched ? `☠ PAIR: ${partner?.avatar} ${partner?.name}` : `☠ VOID (#${currentRoom.toUpperCase()})`}
          </div>
          <div className="mobile-topbar__right">
            <div className="mobile-topbar__souls">
              <div className="soul-pulse" style={{width:7,height:7,borderRadius:'50%',background:'var(--blood-bright)',flexShrink:0,animation:'soulPulse 1.5s ease-in-out infinite'}} />
              {soulCount} {soulCount === 1 ? 'soul' : 'souls'}
            </div>
            <button
              className="mobile-topbar__menu"
              onClick={() => setSidebarOpen(true)}
              aria-label="Open menu"
            >
              ☰
            </button>
          </div>
        </div>

        {/* 1-on-1 voice call header if paired */}
        {isMatched && (
          <div className="voice-header-bar">
            <div className="voice-partner-info">
              <span className="voice-avatar">{partner?.avatar}</span>
              <span className="voice-name">1-on-1 with {partner?.name}</span>
            </div>
            <div className="voice-actions">
              <button
                className={`voice-toggle-btn ${isVoiceActive ? 'mic-active' : ''}`}
                onClick={toggleVoice}
                title={isVoiceActive ? 'Mute Microphone' : 'Enable Microphone'}
              >
                {isVoiceActive ? '🎙️ Mic: ON' : '🔇 Mic: OFF'}
              </button>
              {isPartnerVoiceActive ? (
                <span className="voice-partner-status status-active">🔊 Partner Speaking</span>
              ) : (
                <span className="voice-partner-status status-inactive">🔇 Partner Muted</span>
              )}
              <button className="skip-btn-header" onClick={skipMatch}>
                💀 SKIP PARTNER
              </button>
            </div>
          </div>
        )}

        {/* Admin Console View overlay/tab */}
        {showAdminConsole && isAdmin && (
          <div className="admin-console-overlay">
            <div className="admin-header">
              <h2>👺 VOID OVERSEER PANEL</h2>
              <button className="close-admin-btn" onClick={() => setShowAdminConsole(false)}>✕ Close</button>
            </div>
            <div className="admin-grid">
              {/* Online Users */}
              <div className="admin-section">
                <h3>Wandering Souls Online</h3>
                <div className="admin-table-wrap">
                  <table className="admin-table">
                    <thead>
                      <tr>
                        <th>Identity</th>
                        <th>Realm/Status</th>
                        <th>IP Address</th>
                        <th>Device ID</th>
                        <th>Actions</th>
                      </tr>
                    </thead>
                    <tbody>
                      {adminUsers.map(u => (
                        <tr key={u.id}>
                          <td><span className="t-avatar">{u.avatar}</span> {u.name} {u.id === socketId && "(YOU)"}</td>
                          <td><span className="t-status">{u.status}</span></td>
                          <td><code>{u.ipAddress}</code></td>
                          <td><code>{u.deviceId?.slice(0, 15)}...</code></td>
                          <td>
                            {u.id !== socketId && (
                              <button className="ban-btn-action" onClick={() => executeBan(u)}>EXILE</button>
                            )}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>

              {/* Banned Users */}
              <div className="admin-section">
                <h3>Banned & Exiled Souls</h3>
                <div className="admin-table-wrap">
                  <table className="admin-table">
                    <thead>
                      <tr>
                        <th>Banned IP</th>
                        <th>Banned Device ID</th>
                        <th>Exile Reason</th>
                        <th>Exile Date</th>
                        <th>Actions</th>
                      </tr>
                    </thead>
                    <tbody>
                      {adminBans.length === 0 ? (
                        <tr>
                          <td colSpan="5" style={{textAlign:'center',color:'var(--text-dim)'}}>No souls are currently exiled.</td>
                        </tr>
                      ) : (
                        adminBans.map(b => (
                          <tr key={b.id}>
                            <td><code>{b.ipAddress || 'N/A'}</code></td>
                            <td><code>{b.deviceId ? `${b.deviceId.slice(0, 15)}...` : 'N/A'}</code></td>
                            <td className="reason-col">{b.reason}</td>
                            <td>{new Date(b.createdAt).toLocaleDateString()}</td>
                            <td>
                              <button className="unban-btn-action" onClick={() => executeUnban(b)}>FREE SOUL</button>
                            </td>
                          </tr>
                        ))
                      )}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Messages */}
        <div
          className="messages-area"
          ref={messagesAreaRef}
          onScroll={handleScroll}
        >
          {matchStatus === 'searching' ? (
            <div className="empty-void matching-loader">
              <div className="empty-skull pulse-glow">🔮</div>
              <div className="empty-text">
                WANDERING THE MIST...<br />
                LOOKING FOR ANOTHER SOUL TO PAIR
              </div>
              <div className="matching-spinner" />
              <button className="leave-matching-inner-btn" onClick={leaveMatchmaking}>
                Cancel Search
              </button>
            </div>
          ) : messages.length === 0 ? (
            <div className="empty-void">
              <div className="empty-skull">💀</div>
              <div className="empty-text">
                {isMatched
                  ? `YOU ARE PAIRED WITH ${partner?.avatar} ${partner?.name}.\nSPEAK PRIVATE WHISPERS INTO THE VOID...`
                  : `THE VOID (#${currentRoom.toUpperCase()}) AWAITS\nYOUR WHISPERS...`}
              </div>
            </div>
          ) : (
            messages.map((msg) => (
              <Message
                key={msg.id || msg.ts}
                msg={msg}
                isMine={msg.authorId === socketId}
                socketId={socketId}
                onReport={handleReport}
                onReact={handleReact}
              />
            ))
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Scroll-to-bottom */}
        {showScrollBtn && (
          <button className="scroll-btn" onClick={scrollToBottom} title="Scroll to bottom">
            ↓
          </button>
        )}

        {/* Typing indicator */}
        <TypingBar typingUsers={typingUsers} />

        {/* Image upload preview row if an image is selected */}
        {imagePreview && (
          <div className="image-preview-bar">
            <div className="preview-container">
              <img src={imagePreview} alt="upload preview" className="input-image-preview" />
              <button className="clear-image-preview-btn" onClick={removeAttachedImage} title="Remove image">
                ✕
              </button>
            </div>
            <div className="preview-label">Attached Image Ready for Transmission ({Math.round(imagePreview.length * 0.75 / 1024)} KB)</div>
          </div>
        )}

        {/* Input area */}
        <div className="input-area">
          <div className="input-wrap">
            <textarea
              className="chat-input"
              value={input}
              onChange={handleInputChange}
              onKeyDown={handleKeyDown}
              placeholder={
                !connected
                  ? 'connecting to the dark...'
                  : matchStatus === 'searching'
                  ? 'cannot speak while lost in the mist...'
                  : 'speak into the void...'
              }
              maxLength={MAX_LEN}
              rows={1}
              disabled={!connected || matchStatus === 'searching'}
            />
            <CharCount value={input} max={MAX_LEN} />
          </div>

          {/* File input and clip button */}
          <input
            type="file"
            accept="image/*"
            onChange={handleImageAttach}
            ref={fileInputRef}
            style={{ display: 'none' }}
            disabled={!connected || matchStatus === 'searching'}
          />

          <button
            className="attach-btn"
            onClick={() => fileInputRef.current?.click()}
            disabled={!connected || matchStatus === 'searching'}
            title="Attach image"
          >
            🖼️
          </button>

          <button
            className="send-btn"
            onClick={handleSend}
            disabled={!connected || (!input.trim() && !imagePreview) || matchStatus === 'searching'}
          >
            SEND
          </button>
        </div>
      </main>

      <Toast toasts={toasts} />
    </div>
  );
}
